/* Patch v1.1.3 — cactus toast */
.toast.t-cactus {
  border-color: #22c55e !important;
  color: #15803d;
  box-shadow: 0 4px 18px rgba(34,197,94,.22) !important;
}
body.dark .toast.t-cactus {
  color: #4ade80;
  border-color: #16a34a !important;
}
body.retro .toast.t-cactus {
  border-color: #69f0ae !important;
  color: #a5d6a7 !important;
}

/* PATCH v1.1.7 — Go-to-City HUD button (mobile-only, farming lv5+) */
#hud-city-btn {
  display: none; /* desktop: always hidden */
  align-items: center;
  gap: 4px;
  background: linear-gradient(135deg, #6366f1, #4f46e5);
  border: 1.5px solid #4f46e5;
  border-radius: 20px;
  padding: 4px 10px;
  font-size: 11px;
  font-weight: 700;
  color: #fff;
  cursor: pointer;
  white-space: nowrap;
  font-family: 'Nunito', sans-serif;
  box-shadow: 0 2px 8px rgba(99,102,241,.35);
  transition: opacity .15s, transform .15s;
  flex-shrink: 0;
}
#hud-city-btn:hover  { opacity: .88; transform: scale(1.05); }
#hud-city-btn:active { transform: scale(.95); }
@media (max-width: 680px) {
  #hud-city-btn.city-unlocked { display: flex; }
}
body.dark #hud-city-btn {
  background: linear-gradient(135deg, #4f46e5, #3730a3);
  border-color: #3730a3;
  box-shadow: 0 2px 8px rgba(79,70,229,.4);
}
body.retro #hud-city-btn {
  background: #1a237e !important;
  border: 2px solid #7986cb !important;
  border-radius: 3px !important;
  font-family: 'Press Start 2P', monospace !important;
  font-size: 6.5px !important;
  box-shadow: none !important;
  color: #e8eaf6 !important;
  padding: 4px 7px !important;
}

