(function() {
  /*
   * PATCH v1.1.0 — Energy cost when traveling to other lands
   *
   * Cost table:  home 0 · meadow 10 · riverbank 15 · hillfarm 20 · lowland 25 · volcanic 35
   * Respects the Energy Cost toggle in the Pause menu.
   */
  var TRAVEL_ENERGY = {home:0,meadow:10,riverbank:15,hillfarm:20,lowland:25,volcanic:35};
  var _origTravelTo = window.travelTo;
  window.travelTo = function(landId) {
    if (landId === G.currentLand) { _origTravelTo(landId); return; }
    if (S.energyCost) {
      var cost = (TRAVEL_ENERGY[landId] !== undefined) ? TRAVEL_ENERGY[landId] : 15;
      if (cost > 0) {
        if (G.energy < cost) {
          toast('Not enough energy to travel! Need ' + cost + ' energy \u2014 sleep first. \uD83C\uDF19','error',3500);
          snd('error'); return;
        }
        G.energy = Math.max(0, G.energy - cost);
        if (typeof renderHUD === 'function') renderHUD();
        setTimeout(function() {
          var el = document.getElementById('tp-sub');
          if (el) el.textContent = '\u26A1 Used ' + cost + ' energy for the journey\u2026';
        }, 80);
      }
    }
    _origTravelTo(landId);
  };
  console.log('[Patcher v1.1.0] Travel energy cost patch applied.');
})();

(function() {
  /*
   * PATCH v1.1.1a — Bag button & swipe-up always open the Bag (inv) tab first
   */
  var _origToggleBag = window.toggleBag;
  window.toggleBag = function() { window.setTab('inv'); _origToggleBag(); };
  var _origOpenSheet = window.openSheet;
  window.openSheet = function() { window.setTab('inv'); _origOpenSheet(); };
  console.log('[Patcher v1.1.1a] Bag default-tab patch applied.');
})();

(function() {
  /*
   * PATCH v1.1.1b — Mobile map fullscreen: SVG map on top, land list scrollable below
   */
  var _orig = window.buildMapFullscreen;
  window.buildMapFullscreen = function() {
    if (window.innerWidth > 680) { _orig(); return; }
    var body = document.getElementById('mf-body');
    var owned = G.lands || {};
    var totalRent = Object.entries(owned).reduce(function(s,e){
      var l=e[1];
      if (l.rented&&!l.owned){var p=LAND_PLOTS[e[0]];return s+(p?Math.round(p.rentDay*(1+(l.interestAccrued||0))):0);}
      return s;
    },0);
    var rentEl = document.getElementById('mf-rent-info');
    if (rentEl) rentEl.textContent = totalRent>0 ? '\u23F3 Rent: '+totalRent+'g/day' : '';
    var mapHtml = '<div style="position:relative;width:100%;aspect-ratio:16/9;border-radius:12px;overflow:hidden;border:2px solid var(--ui-border)">'+buildMapSVG(owned,false)+'</div>';
    var cards = '';
    if ((G.currentLand||'home') !== 'home') cards += '<button class="map-return-btn" onclick="travelTo(\'home\')">\uD83C\uDFE1 Return to Home Farm</button>';
    cards += '<div class="s-sec" style="margin-top:12px">\uD83D\uDDFA Available Land</div>';
    if (totalRent>0) cards += '<div style="padding:7px 10px;background:#fef9c3;border:1px solid #fde68a;border-radius:10px;font-size:10px;font-weight:700;color:#92400e;margin-bottom:8px">\u23F3 Active rent: <b>'+totalRent+'g/day</b> deducted each night</div>';
    var danger = Object.entries(owned).filter(function(e){return e[1].rented&&!e[1].owned&&(e[1].debtDays||0)>=5;});
    if (danger.length) cards += '<div class="mf-debt-warning">\uD83D\uDEA8 <b>DANGER!</b> '+danger.length+' plot(s) have missed rent 5+ days! Pay before day 7 or crops are seized!</div>';
    Object.entries(LAND_PLOTS).forEach(function(entry) {
      var id=entry[0],plot=entry[1],land=owned[id]||{};
      if (id==='city') return;
      var io=land.owned,ir=land.rented&&!land.owned;
      var er=ir?Math.round(plot.rentDay*(1+(land.interestAccrued||0))):plot.rentDay;
      var hd=(land.debtG||0)>0,dd=land.debtDays||0,fc=plot.fertility.toLowerCase();
      cards+='<div class="land-card"><div class="land-card-top"><div class="land-card-left">';
      cards+='<span class="land-em">'+plot.e+'</span>';
      cards+='<div><div class="land-name">'+plot.n+' <span class="land-fert '+fc+'">'+plot.fertility+'</span></div></div>';
      cards+='</div></div>';
      cards+='<div class="land-desc">'+plot.desc+'</div>';
      cards+='<div class="land-price-row"><span class="land-price-tag">\uD83D\uDCB0 Buy: '+plot.buyPrice+'g</span><span class="land-rent-tag">\u00B7 Rent: '+plot.rentDay+'g/day</span><span class="land-interest-tag">(+'+Math.round(plot.interestRate*100)+'% interest/season)</span></div>';
      if (io) {
        cards+='<span class="land-owned-badge">\u2713 You own this land</span>';
        cards+='<div class="land-btn-row"><button class="land-btn map-travel-btn" onclick="travelTo(\''+id+'\')">\uD83D\uDE80 Go to this Farm</button></div>';
      } else if (ir) {
        var dw=dd>0?' \u00B7 \u23F0 '+(7-dd)+'d left':'';
        cards+='<span class="land-rented-badge">\u23F3 Renting \u00B7 '+er+'g/day'+(hd?' \u00B7 \u26A0\uFE0F Debt: '+Math.round(land.debtG)+'g'+dw:'')+' </span>';
        cards+='<div class="land-btn-row">';
        cards+='<button class="land-btn land-btn-buy" id="mfbl-'+id+'" '+(G.gold>=plot.buyPrice?'':'disabled')+'>Buy Out '+plot.buyPrice+'g</button>';
        cards+='<button class="land-btn land-btn-leave" id="mfll-'+id+'">Leave Plot</button>';
        cards+='<button class="land-btn map-travel-btn" onclick="travelTo(\''+id+'\')">\uD83D\uDE80 Go Here</button>';
        cards+='</div>';
      } else {
        cards+='<div class="land-btn-row">';
        cards+='<button class="land-btn land-btn-buy" id="mfbl-'+id+'" '+(G.gold>=plot.buyPrice?'':'disabled')+'>Buy '+plot.buyPrice+'g</button>';
        cards+='<button class="land-btn land-btn-rent" id="mfrl-'+id+'" '+(G.gold>=plot.rentDay?'':'disabled')+'>Rent '+plot.rentDay+'g/day</button>';
        cards+='</div>';
      }
      cards+='</div>';
    });
    // City District — special non-farm land rendered separately
    var _cp = LAND_PLOTS['city'];
    if (_cp) {
      var _reqLv = _cp.reqLevel || 5;
      var _curLv = (G.farmingLevel || (G.skills && G.skills.farming) || 1);
      var _unlocked = _curLv >= _reqLv;
      cards += '<div class="land-card">';
      cards += '<div class="land-card-top"><div class="land-card-left">';
      cards += '<span class="land-em">' + _cp.e + '</span>';
      cards += '<div><div class="land-name">' + _cp.n + ' <span class="land-fert" style="background:#16a34a;color:#fff;padding:1px 7px;border-radius:99px;font-size:9px;font-weight:800">FREE</span></div></div>';
      cards += '</div></div>';
      cards += '<div class="land-desc">' + _cp.desc + '</div>';
      if (_unlocked) {
        cards += '<div class="land-btn-row"><button class="land-btn map-travel-btn" onclick="openCityScreen()">\uD83C\uDFD9\uFE0F Enter City</button></div>';
      } else {
        cards += '<div style="margin:6px 0;padding:8px 10px;background:#92400e22;border:1px solid #92400e55;border-radius:8px;font-size:10px;font-weight:700;color:#92400e">\uD83D\uDD12 Requires Farming Level ' + _reqLv + ' \u2014 you are Lv.' + _curLv + '</div>';
      }
      cards += '</div>';
    }
    cards+='<div class="market-note" style="margin-top:8px;margin-bottom:20px">\uD83D\uDCA1 <b>Land Tips:</b><br>Owned land is yours forever. Rented land charges daily \u2014 miss 7 days rent and crops are seized. Leave any rented plot anytime, debt forgiven.</div>';
    body.style.overflowY='auto';
    body.innerHTML='<div style="padding:12px 12px 8px">'+mapHtml+'</div><div style="padding:0 12px 16px">'+cards+'</div>';
    Object.keys(LAND_PLOTS).forEach(function(id){
      var bl=document.getElementById('mfbl-'+id),rl=document.getElementById('mfrl-'+id),ll=document.getElementById('mfll-'+id);
      if(bl)bl.addEventListener('click',function(){buyLand(id);buildMapFullscreen();});
      if(rl)rl.addEventListener('click',function(){rentLand(id);buildMapFullscreen();});
      if(ll)ll.addEventListener('click',function(){leaveLand(id);buildMapFullscreen();});
    });
  };
  console.log('[Patcher v1.1.1b] Mobile map layout patch applied.');
})();

(function() {
  /*
   * PATCH v1.1.2 — Soil-Crop Growth System
   *
   * Crop growth speed is now tied to land fertility. The days-needed
   * threshold is multiplied per land — more fertile = fewer days to ready.
   *
   *  Land        Multiplier   Effect
   *  ──────────────────────────────────────────
   *  home        1.00x        Baseline
   *  meadow      1.22x        22% slower (poor dry soil)
   *  riverbank   0.97x        3% faster  (moist average soil)
   *  hillfarm    0.90x        10% faster (elevated sun exposure)
   *  lowland     0.78x        22% faster (deep rich alluvial)
   *  volcanic    0.63x        37% faster (mineral-rich ash)
   *
   * Crop-soil affinity: native crops grow an extra 20% faster on
   * their home soil, stacked on top of the base bonus above.
   *
   *  meadow    → garlic, mushroom, tulip, parsnip
   *  riverbank → strawberry, blueberry, cranberry, carrot
   *  hillfarm  → potato, cauliflower, corn, sunflower
   *  lowland   → melon, pumpkin, eggplant, yam
   *  volcanic  → pepper, tomato, eggplant, cranberry
   *
   * No save-format changes. crop.days is still a raw counter;
   * only the ready threshold is adjusted per land in cropStage().
   */

  var SOIL_MULT = {
    home:      1.00,
    meadow:    1.22,
    riverbank: 0.97,
    hillfarm:  0.90,
    lowland:   0.78,
    volcanic:  0.63
  };

  var AFFINITY = {
    meadow:    ['garlic','mushroom','tulip','parsnip'],
    riverbank: ['strawberry','blueberry','cranberry','carrot'],
    hillfarm:  ['potato','cauliflower','corn','sunflower'],
    lowland:   ['melon','pumpkin','eggplant','yam'],
    volcanic:  ['pepper','tomato','eggplant','cranberry']
  };

  var AFFINITY_EXTRA = 0.80; // native crops get an extra 20% speedup

  /* ── Core: adjusted days needed for crop on a given land ── */
  window.getEffectiveDays = function(cropType, landId) {
    if (!CROPS[cropType]) return 1;
    var base = CROPS[cropType].days;
    var mult = (SOIL_MULT[landId] !== undefined) ? SOIL_MULT[landId] : 1.00;
    if ((AFFINITY[landId] || []).indexOf(cropType) !== -1) mult *= AFFINITY_EXTRA;
    return Math.max(1, Math.round(base * mult));
  };

  /* ── Override cropStage: use soil-adjusted threshold ── */
  window.cropStage = function(c) {
    if (!c) return -1;
    var d = getEffectiveDays(c.type, G.currentLand || 'home');
    if (c.days >= d)                   return 3;
    if (c.days >= Math.ceil(d * 0.66)) return 2;
    if (c.days >= Math.ceil(d * 0.33)) return 1;
    return 0;
  };

  /* ── renderFarm wrapper: fix days-badge to show adjusted remaining days ── */
  var _origRF = window.renderFarm;
  window.renderFarm = function() {
    _origRF();
    var landId = G.currentLand || 'home';
    if (landId === 'home') return; // mult is 1.0, badge already correct
    var grid = document.getElementById('farm-grid');
    if (!grid) return;
    for (var r = 0; r < GH; r++) {
      for (var c = 0; c < GW; c++) {
        var el = grid.children[r * GW + c];
        if (!el) continue;
        var tile = G.farm[r] && G.farm[r][c];
        if (!tile || !tile.crop) continue;
        if (cropStage(tile.crop) === 3) continue; // already ready, no badge
        var badge = el.querySelector('.days-badge');
        if (!badge) continue;
        var rem = Math.max(0, getEffectiveDays(tile.crop.type, landId) - tile.crop.days);
        badge.textContent = Math.ceil(rem) + 'd';
      }
    }
  };

  /* ── renderLandBanner wrapper: append growth speed indicator ── */
  var _origRLB = window.renderLandBanner;
  window.renderLandBanner = function() {
    _origRLB();
    var cl = G.currentLand || 'home';
    if (cl === 'home') return;
    var banner = document.getElementById('land-banner');
    if (!banner || !banner.classList.contains('show')) return;
    var mult = SOIL_MULT[cl] || 1.0;
    var pct  = Math.round(Math.abs(1 - mult) * 100);
    if (!pct) return;
    var lbl = mult < 1.0
      ? ' \u00B7 \u26A1 +' + pct + '% faster crops'
      : ' \u00B7 \uD83D\uDC22 \u2212' + pct + '% slower crops';
    if (banner.textContent.indexOf('faster') === -1 && banner.textContent.indexOf('slower') === -1) {
      banner.textContent += lbl;
    }
  };

  /* ── Helper: build soil info HTML snippet for a land card ── */
  function _soilTag(landId) {
    var mult = SOIL_MULT[landId] || 1.0;
    var affs = AFFINITY[landId] || [];
    var pct  = Math.round(Math.abs(1 - mult) * 100);
    var parts = [];
    if (pct > 0) {
      parts.push(mult < 1.0
        ? '<span style="color:#16a34a;font-weight:800">\u26A1 +' + pct + '% faster growth</span>'
        : '<span style="color:#b45309;font-weight:800">\uD83D\uDC22 \u2212' + pct + '% slower growth</span>');
    }
    if (affs.length) {
      var ems   = affs.map(function(t){ return CROPS[t] ? CROPS[t].e : ''; }).join('');
      var names = affs.map(function(t){ return CROPS[t] ? CROPS[t].n : t; }).join(', ');
      parts.push('<span style="color:var(--text-muted)" title="Native crops grow an extra 20% faster here: ' + names + '">\uD83C\uDF1F Native: ' + ems + '</span>');
    }
    if (!parts.length) return '';
    return '<div class="soil-growth-tag" style="display:flex;gap:6px;align-items:center;flex-wrap:wrap;margin:3px 0 4px;padding:3px 0;font-size:10px;border-top:1px dashed var(--ui-border)">'
      + parts.join('<span style="opacity:.35"> \u00B7 </span>')
      + '</div>';
  }

  /* ── buildMap wrapper: inject soil tag into side-panel land cards ── */
  var _origBM = window.buildMap;
  window.buildMap = function() {
    var html = _origBM();
    Object.entries(LAND_PLOTS).forEach(function(entry) {
      var id = entry[0], plot = entry[1];
      var tag = _soilTag(id);
      if (!tag) return;
      var anchor = '<div class="land-desc">' + plot.desc + '</div>';
      html = html.replace(anchor, anchor + tag);
    });
    return html;
  };

  /* ── buildMapFullscreen wrapper: inject soil tag into fullscreen land cards ── */
  var _origBMF = window.buildMapFullscreen;
  window.buildMapFullscreen = function() {
    _origBMF();
    var body = document.getElementById('mf-body');
    if (!body) return;
    var descs  = body.querySelectorAll('.land-desc');
    var landIds = Object.keys(LAND_PLOTS);
    descs.forEach(function(desc, i) {
      var landId = landIds[i];
      if (!landId) return;
      if (desc.nextElementSibling && desc.nextElementSibling.classList.contains('soil-growth-tag')) return;
      var tag = _soilTag(landId);
      if (tag) desc.insertAdjacentHTML('afterend', tag);
    });
  };

  console.log('[Patcher v1.1.2] Soil-crop growth system applied.');
})();

(function(){
  /* ── ENERGY BUG FIX ──────────────────────────────────────────
     Root cause: the #tog-energy checkbox onchange only set
     S.energyCost in memory but never called saveS(). Because
     saveAll() (autosave, 30s) DOES call saveS(), an accidental
     toggle-off would silently persist. On next load, loadS()
     merges {energyCost:false} into S, causing useE() to skip
     energy deduction for every tool (hoe, water, scythe).

     Fix 1 – restore the setting if it was corrupted:
  */
  if (S.energyCost === false) {
    console.log('[Patch v1.0.1] energyCost was false — restoring to true and saving.');
    S.energyCost = true;
    if (typeof saveS === 'function') saveS();
  }

  /*  Fix 2 – make the toggle persist its change immediately,
      same as the sounds toggle already does:
  */
  const togE = document.getElementById('tog-energy');
  if (togE) {
    togE.onchange = function () {
      S.energyCost = this.checked;
      if (typeof saveS === 'function') saveS();
    };
  }

  /* ── CACTUS TOAST FIX ────────────────────────────────────────
     showCactusHmm() was calling toast('hmmm','info') which gets
     the default blue border (t-info). Override it to use a
     custom green-outlined t-cactus class with 🌵👀.
  */
  window.showCactusHmm = function () {
    if (!S.toasts) return;
    const id = 'cactus-' + Date.now();
    const el = document.createElement('div');
    el.className = 'toast t-cactus';
    el.id = id;
    el.textContent = '🌵👀 hmmm';
    const wrap = document.getElementById('toast-wrap');
    if (!wrap) return;
    wrap.appendChild(el);
    setTimeout(() => {
      el.classList.add('toast-out');
      setTimeout(() => el.remove(), 220);
    }, 2200);
  };

  console.log('[Patch v1.0.1] Applied — energy bug fixed, cactus toast updated.');
})();

(function() {
  /*
   * PATCH v1.1.5 — Fix: City District card duplicated + reorder to bottom
   *
   * Fix 1 – Deduplicate: 'city' was rendered twice (once by the special
   * level-gate path in script.js and once by the LAND_PLOTS loop).
   * Keep only the first occurrence (the level-gated version).
   *
   * Fix 2 – Reorder: move the City District card to the very bottom of
   * the land list, after Volcanic, in both the fullscreen map and the
   * side-panel map tab.
   */

  function dedupAndSink(container) {
    var seen = {};
    var cityCard = null;
    /* Deduplicate first */
    container.querySelectorAll('.land-card').forEach(function(card) {
      var nameEl = card.querySelector('.land-name');
      var key = nameEl ? nameEl.textContent.replace(/\s+/g, ' ').trim() : null;
      if (!key) return;
      if (seen[key]) {
        card.remove();
      } else {
        seen[key] = true;
        if (key.indexOf('City District') !== -1) cityCard = card;
      }
    });
    /* Move city card to bottom of the last card's parent */
    if (cityCard && cityCard.parentNode) {
      cityCard.parentNode.appendChild(cityCard);
    }
  }

  /* ── Fullscreen map ── */
  var _prevBMF = window.buildMapFullscreen;
  window.buildMapFullscreen = function() {
    _prevBMF.apply(this, arguments);
    var body = document.getElementById('mf-body');
    if (!body) return;
    dedupAndSink(body);
  };

  /* ── Side-panel map ── */
  var _prevBM = window.buildMap;
  if (typeof _prevBM === 'function') {
    window.buildMap = function() {
      var html = _prevBM.apply(this, arguments);
      var tmp = document.createElement('div');
      tmp.innerHTML = html;
      dedupAndSink(tmp);
      return tmp.innerHTML;
    };
  }

  console.log('[Patcher v1.1.5] City District dedup + sink-to-bottom applied.');
})();

(function() {
  /*
   * PATCH v1.1.6 — Enhanced Soil & Affinity System
   *
   * Changes vs v1.1.2:
   *  · Native-crop affinity bonus: 20% → 45% faster  (AFFINITY_EXTRA 0.80 → 0.55)
   *  · Volcanic soil:   37% → 48% faster  (mult 0.63 → 0.52)
   *  · Rich Lowland:    22% → 35% faster  (mult 0.78 → 0.65)
   *  · City District card: soil tag hidden entirely (not a farmable land)
   *  · Soil tag assignment fixed: matched by land name, not array index,
   *    so cards always show the correct soil stats regardless of order.
   *
   *  Full table after patch:
   *  Land        Mult    Growth
   *  home        1.00    baseline
   *  meadow      1.22    −22% slower
   *  riverbank   0.97    +3%  faster
   *  hillfarm    0.90    +10% faster
   *  lowland     0.65    +35% faster  (↑ from +22%)
   *  volcanic    0.52    +48% faster  (↑ from +37%)
   *  city        —       no soil tag shown
   */

  var SOIL_MULT2 = {
    home:      1.00,
    meadow:    1.22,
    riverbank: 0.97,
    hillfarm:  0.90,
    lowland:   0.65,
    volcanic:  0.52
  };

  var AFFINITY2 = {
    meadow:    ['garlic','mushroom','tulip','parsnip'],
    riverbank: ['strawberry','blueberry','cranberry','carrot'],
    hillfarm:  ['potato','cauliflower','corn','sunflower'],
    lowland:   ['melon','pumpkin','eggplant','yam'],
    volcanic:  ['pepper','tomato','eggplant','cranberry']
  };

  var AFFINITY_EXTRA2 = 0.55; // ×0.55 days = 45% faster for native crops

  /* Override getEffectiveDays globally so cropStage + day-badges use new values */
  window.getEffectiveDays = function(cropType, landId) {
    if (!CROPS[cropType]) return 1;
    var base = CROPS[cropType].days;
    var mult = (SOIL_MULT2[landId] !== undefined) ? SOIL_MULT2[landId] : 1.00;
    if ((AFFINITY2[landId] || []).indexOf(cropType) !== -1) mult *= AFFINITY_EXTRA2;
    return Math.max(1, Math.round(base * mult));
  };

  /* Build soil tag HTML with updated values. Returns '' for city or home. */
  function _soilTag2(landId) {
    if (!landId || landId === 'city' || landId === 'home') return '';
    var mult = SOIL_MULT2[landId];
    if (mult === undefined) return '';
    var affs = AFFINITY2[landId] || [];
    var pct  = Math.round(Math.abs(1 - mult) * 100);
    var parts = [];
    if (pct > 0) {
      parts.push(mult < 1.0
        ? '<span style="color:#16a34a;font-weight:800">\u26A1 +' + pct + '% faster growth</span>'
        : '<span style="color:#b45309;font-weight:800">\uD83D\uDC22 \u2212' + pct + '% slower growth</span>');
    }
    if (affs.length) {
      var ems   = affs.map(function(t){ return CROPS[t] ? CROPS[t].e : ''; }).join('');
      var names = affs.map(function(t){ return CROPS[t] ? CROPS[t].n : t; }).join(', ');
      parts.push('<span style="color:var(--text-muted)" title="Native crops grow 45% faster here: ' + names + '">\uD83C\uDF1F Native: ' + ems + '</span>');
    }
    if (!parts.length) return '';
    return '<div class="soil-growth-tag" style="display:flex;gap:6px;align-items:center;flex-wrap:wrap;margin:3px 0 4px;padding:3px 0;font-size:10px;border-top:1px dashed var(--ui-border)">'
      + parts.join('<span style="opacity:.35"> \u00B7 </span>')
      + '</div>';
  }

  /* Build plot-name → land-id lookup from LAND_PLOTS */
  function _nameMap() {
    var m = {};
    Object.entries(LAND_PLOTS).forEach(function(e) { m[e[1].n] = e[0]; });
    return m;
  }

  /*
   * Strip old soil tags and re-inject correct ones by NAME lookup
   * (fixes the index-offset bug where tags were assigned to wrong cards
   * because home/city aren't always in the visible list).
   */
  function _retagCards(root) {
    var nm = _nameMap();
    root.querySelectorAll('.land-card').forEach(function(card) {
      /* Remove any old soil tag */
      var old = card.querySelector('.soil-growth-tag');
      if (old) old.remove();
      /* Identify land by matching the card's .land-name text against LAND_PLOTS */
      var nameEl = card.querySelector('.land-name');
      if (!nameEl) return;
      var cardText = nameEl.textContent.replace(/\s+/g, ' ').trim();
      var landId = null;
      Object.keys(nm).forEach(function(plotName) {
        if (cardText.indexOf(plotName) !== -1) landId = nm[plotName];
      });
      if (!landId || landId === 'city') return; // city: no soil tag
      var tag = _soilTag2(landId);
      if (tag) {
        var desc = card.querySelector('.land-desc');
        if (desc) desc.insertAdjacentHTML('afterend', tag);
      }
    });
  }

  /* ── Fullscreen map ── */
  var _prevBMF = window.buildMapFullscreen;
  window.buildMapFullscreen = function() {
    _prevBMF.apply(this, arguments);
    var body = document.getElementById('mf-body');
    if (body) _retagCards(body);
  };

  /* ── Side-panel map ── */
  var _prevBM = window.buildMap;
  if (typeof _prevBM === 'function') {
    window.buildMap = function() {
      var html = _prevBM.apply(this, arguments);
      var tmp = document.createElement('div');
      tmp.innerHTML = html;
      _retagCards(tmp);
      return tmp.innerHTML;
    };
  }

  console.log('[Patcher v1.1.6] Enhanced soil system: affinity 45%, volcanic +48%, lowland +35%, city card clean, tag index-bug fixed.');
})();

(function() {
  /*
   * PATCH v1.1.7 — Go-to-City HUD button (mobile-only, farming lv5+)
   *
   * Adds a "🏙️ City" shortcut button directly in the HUD bar.
   *   • Rendered in #hud so it travels with every HUD repaint
   *   • Hidden on desktop via CSS (max-width:680px guard)
   *   • Shown only when farming level >= 5  (JS adds .city-unlocked)
   *   • Clicking fires the normal city travel animation then opens the
   *     Stock Market — identical to pressing "Visit City" from the Map tab
   *   • Does NOT touch the map section in any way
   */

  /* ── City shortcut handler ────────────────────────────── */
  window.hudGoToCity = function() {
    var fLv = (typeof getLevel === 'function')
      ? getLevel((G.skills && G.skills.farming && G.skills.farming.xp) || 0)
      : 1;
    if (fLv < 5) {
      toast(
        '\uD83D\uDD12 Farming Level 5 required for the City! (You are Lv.' + fLv + ')',
        'error', 3200
      );
      if (typeof snd === 'function') snd('error');
      return;
    }
    /* Use the travel-animation path when available (preferred) */
    if (typeof _travelAnimThenCity === 'function') {
      _travelAnimThenCity();
    } else if (typeof openCityScreen === 'function') {
      openCityScreen();
    }
  };

  /* ── Wrap renderHUD to keep button visibility in sync ──── */
  var _origRenderHUD = window.renderHUD;
  window.renderHUD = function() {
    _origRenderHUD.apply(this, arguments);
    var btn = document.getElementById('hud-city-btn');
    if (!btn) return;
    var fLv = (typeof getLevel === 'function')
      ? getLevel((G.skills && G.skills.farming && G.skills.farming.xp) || 0)
      : 1;
    /* .city-unlocked lets the @media rule make it visible on mobile */
    btn.classList.toggle('city-unlocked', fLv >= 5);
  };

  console.log('[Patcher v1.1.7] Go-to-City HUD button (mobile, lv5+) applied.');
})();
